esqlQuery.esql:
FROM metrics-redisenterprise.otel-default
| WHERE bdb_avg_latency IS NOT NULL
| STATS avg_latency_s = AVG(bdb_avg_latency) BY bdb, cluster
| EVAL avg_latency_ms = ROUND(avg_latency_s * 1000, 2)
// Threshold: 5ms average latency — adjust based on your SLA
// Redis should deliver sub-millisecond responses; sustained >5ms warrants investigation
// Common causes: memory pressure, fork operations (AOF/RDB), hot shards
| WHERE avg_latency_ms > 5
| SORT avg_latency_ms DESC
